using CertDesk.Models; using CertDesk.Services; using System.Data;
namespace CertDesk.Forms;
public sealed class CertificateEditForm:Form
{ public CertificateEditForm(Certificate e,CertificateService service){Text="Сертификат"; StartPosition=FormStartPosition.CenterParent; Width=430; Height=620; var p=new FlowLayoutPanel{Dock=DockStyle.Fill,FlowDirection=FlowDirection.TopDown,Padding=new Padding(16)}; ComboBox emp=Ui.Combo(), auth=Ui.Combo(), tok=Ui.Combo(), sig=Ui.Combo(); Bind(emp,LookupService.Employees()); Bind(auth,LookupService.Authorities()); var tokens=LookupService.Tokens(); tokens.Rows.Add(DBNull.Value,"— без токена —"); Bind(tok,tokens); sig.Items.AddRange(["SES","NES","QES"]); TextBox serial=Ui.TextBox(), purpose=Ui.TextBox(); DateTimePicker issued=new(){Width=260}, from=new(){Width=260}, to=new(){Width=260}; serial.Text=e.SerialNumber; purpose.Text=e.Purpose; issued.Value=e.IssuedAt==default?DateTime.Today:e.IssuedAt; from.Value=e.ValidFrom==default?DateTime.Today:e.ValidFrom; to.Value=e.ValidTo==default?DateTime.Today.AddYears(1):e.ValidTo; sig.SelectedItem=e.SignatureType; Set(emp,e.EmployeeId); Set(auth,e.AuthorityId); Set(tok,e.TokenId); foreach(Control c in [Ui.Label("Владелец"),emp,Ui.Label("Удостоверяющий центр"),auth,Ui.Label("Токен"),tok,Ui.Label("Серийный номер"),serial,Ui.Label("Тип подписи"),sig,Ui.Label("Дата выдачи"),issued,Ui.Label("Действует с"),from,Ui.Label("Действует до"),to,Ui.Label("Назначение"),purpose]) p.Controls.Add(c); var save=Ui.Button("Сохранить"); p.Controls.Add(save); Controls.Add(p); save.Click+=(_,_)=>{try{e.EmployeeId=Val(emp)??0;e.AuthorityId=Val(auth)??0;e.TokenId=Val(tok);e.SerialNumber=serial.Text;e.SignatureType=sig.Text;e.IssuedAt=issued.Value;e.ValidFrom=from.Value;e.ValidTo=to.Value;e.Purpose=purpose.Text;service.Save(e);DialogResult=DialogResult.OK;Close();}catch(Exception ex){Ui.Error(ex);}};}
 static void Bind(ComboBox c,DataTable dt){c.DataSource=dt;c.ValueMember="id";c.DisplayMember="name";} static int? Val(ComboBox c)=>c.SelectedValue==DBNull.Value||c.SelectedValue==null?null:Convert.ToInt32(c.SelectedValue); static void Set(ComboBox c,int? v){if(v.HasValue)c.SelectedValue=v.Value;}
}
